insert into caravan_navi_comment values (1, -470.0, 1, 'クローチェ', 0.0, 2, 1.47, 'いらっしゃいませっ♪\\nキャラバンコインを使って\\n買い物ができますよっ！', '2023/06/30 12:00:00', 10001, 1, '2023/09/22 14:59:59', 2002, 126401);
insert into caravan_navi_comment values (2, -470.0, 1, 'クローチェ', 0.0, 1, 2.15, '素敵な品が揃ってるので\\nたーっくさん買っていって\\nくださいねっ♪', '2023/06/30 12:00:00', 10002, 2, '2023/09/22 14:59:59', 2002, 126401);
insert into caravan_navi_comment values (1, -470.0, 1, 'ライラエル', 0.0, 2, 0.0, 'ショップへようこそ\\nキャラバンコインはこちら\\nで買い物に使えますよ', '2023/06/30 12:00:00', 10003, 2, '2023/09/22 14:59:59', 2002, 126501);
insert into caravan_navi_comment values (2, -470.0, 1, 'ライラエル', 0.0, 1, 0.0, 'こちらのショップで\\n買い物をして、素敵な\\n旅を楽しんでくださいね', '2023/06/30 12:00:00', 10004, 1, '2023/09/22 14:59:59', 2002, 126501);
insert into caravan_navi_comment values (1, -470.0, 2, 'リンド', 0.0, 2, 0.0, 'いらっしゃいませ\\nキャラバンコインを使って\\nお買い物ができますよ', '2023/09/15 15:00:00', 10005, 2, '2023/12/22 14:59:59', 2002, 127702);
insert into caravan_navi_comment values (2, -470.0, 2, 'リンド', 0.0, 2, 0.0, 'ショップの掃除は完璧です\\n姫さま直営のお店として\\n当然のことですから', '2023/09/15 15:00:00', 10006, 2, '2023/12/22 14:59:59', 2002, 127702);
insert into caravan_navi_comment values (1, -470.0, 2, 'ヴルム', 0.0, 1, 0.0, 'ショップへようこそ\\nキャラバンコインと品物を\\n交換できるんで、よければ', '2023/09/15 15:00:00', 10007, 1, '2023/12/22 14:59:59', 2002, 127802);
insert into caravan_navi_comment values (2, -470.0, 2, 'ヴルム', 0.0, 1, 6.5, 'なんで店番なんか…\\nま、やりますけど\\n好きな品物をどうぞ', '2023/09/15 15:00:00', 10008, 2, '2023/12/22 14:59:59', 2002, 127802);
insert into caravan_navi_comment values (1, -470.0, 3, 'アネモネ', 0.0, 1, 0.0, '──いらっしゃいませ\\n買い物しても、いいですよ\\nキャラバンコインがあれば', '2023/12/15 15:00:00', 10009, 2, '2024/03/22 14:59:59', 2002, 129602);
insert into caravan_navi_comment values (2, -470.0, 3, 'アネモネ', 0.0, 1, 0.0, '──もっと笑顔がほしい？\\nいくらコインを積まれても\\n売れない物はありますから', '2023/12/15 15:00:00', 10010, 2, '2024/03/22 14:59:59', 2002, 129602);
insert into caravan_navi_comment values (1, -470.0, 3, 'ネフィ=ネラ', 0.0, 1, 0.0, 'ようこそおいでなんし\\nキャラバンコインをこちら\\nで交換して進ぜんしょう', '2023/12/15 15:00:00', 10011, 1, '2024/03/22 14:59:59', 2002, 129701);
insert into caravan_navi_comment values (2, -470.0, 3, 'ネフィ=ネラ', 0.0, 1, 6.2, 'ところで、お前さまは\\nいくらで贖えるのか喃？\\n──フフ、冗談でありんす', '2023/12/15 15:00:00', 10012, 2, '2024/03/22 14:59:59', 2002, 129701);
insert into caravan_navi_comment values (1, -470.0, 4, 'カノン', 0.0, 5, 3.1, 'い、いらっしゃいませっ！\\n…くっ…このあたくし様が\\n店番なんて…屈辱ですわっ', '2024/03/15 15:00:00', 10013, 3, '2024/06/22 14:59:59', 2002, 130301);
insert into caravan_navi_comment values (2, -470.0, 4, 'カノン', 0.0, 2, 6.15, 'あら、あたくしをご所望？\\nお生憎様、そんな小銭では\\n…買えちゃうんですの！？', '2024/03/15 15:00:00', 10014, 3, '2024/06/22 14:59:59', 2002, 130301);
insert into caravan_navi_comment values (1, -470.0, 4, 'ナーナ', 0.0, 2, 0.0, 'いらっしゃいませ～♪\\nきゃらばんこいん？を\\n交換できるんだってー', '2024/03/15 15:00:00', 10015, 2, '2024/06/22 14:59:59', 2002, 130401);
insert into caravan_navi_comment values (2, -470.0, 4, 'ナーナ', 0.0, 1, 3.35, '甘いのくれたら、\\nお礼にナーナの拾った\\n松ぼっくりあげちゃうよ！', '2024/03/15 15:00:00', 10016, 2, '2024/06/22 14:59:59', 2002, 130401);
insert into caravan_navi_comment values (1, -470.0, 5, 'ホウオウ', 0.0, 1, 0.0, 'ショップへようこそ\\nこの鳳凰が、皆さんに\\n祝福を差し上げましょう', '2024/06/15 15:00:00', 10017, 1, '2024/09/22 14:59:59', 2002, 130502);
insert into caravan_navi_comment values (2, -470.0, 5, 'ホウオウ', 0.0, 1, 3.18, 'ほーちゃんと呼ぶ権利は\\n売っていませんよ？\\n騎士さんへの、特別です！', '2024/06/15 15:00:00', 10018, 2, '2024/09/22 14:59:59', 2002, 130502);
insert into caravan_navi_comment values (3, -470.0, 5, 'ホウオウ', 0.0, 4, 0.0, 'うﾞぇぇえんっ！まﾞだごの\\n格好になっぢゃいまじだ！\\n寄付をお願いじまず～っ！', '2024/06/15 15:00:00', 10019, 4, '2024/09/22 14:59:59', 2002, 130503);
insert into caravan_navi_comment values (1, -470.0, 5, 'ネア', 0.0, 2, 4.9, 'おっすー♪\\nなんでも交換してけー\\nカリザきゅん以外で', '2024/06/15 15:00:00', 10020, 1, '2024/09/22 14:59:59', 2002, 123301);
insert into caravan_navi_comment values (2, -470.0, 5, 'ネア', 0.0, 2, 4.8, 'ところで、騎士きゅんは\\nおいくら万ルピ？\\nジョーダンぬ・き・で♡', '2024/06/15 15:00:00', 10021, 1, '2024/09/22 14:59:59', 2002, 123301);
